# aggregator/dedup.py
# Weekly aggregation job: reads new signals and merges into friction backlog

import re
from difflib import SequenceMatcher

def similarity(a: str, b: str) -> float:
    return SequenceMatcher(None, a.lower(), b.lower()).ratio()

def find_existing(title: str, component: str, backlog: list) -> "FrictionItem | None":
    for item in backlog:
        if item.component != component:
            continue
        if item.status in ("fixed", "wont-fix"):
            continue
        if similarity(item.title, title) > 0.70:
            return item
    return None

def ingest_signal(raw: dict, backlog: list) -> None:
    """
    raw = {"title": str, "component": str, "source": str,
           "team": str | None, "severity": str}
    """
    existing = find_existing(raw["title"], raw["component"], backlog)
    if existing:
        existing.signal_count += 1
        existing.sources.append(raw["source"])
        if raw.get("team") and raw["team"] not in existing.affected_teams:
            existing.affected_teams.append(raw["team"])
    else:
        backlog.append(FrictionItem(
            id=generate_id(),
            title=raw["title"],
            component=raw["component"],
            severity=raw["severity"],
            sources=[raw["source"]],
            affected_teams=[raw["team"]] if raw.get("team") else [],
            signal_count=1,
            user_impact="",   # filled in during triage
            root_cause=None,
            effort="unknown",
            priority="P3",    # default; adjusted during triage
            owner=None,
            status="new",
        ))
